            case 2:
                for (int i = 1; i <= H; ++i) {
                    for (int j = W; j > X; --j) {
                        board[i][j] += 1;
                    }
                }
                break;
            case 3:
                for (int i = 1; i <= Y; ++i) {
                    for (int j = 1; j <= W; ++j) {
                        board[i][j] += 1;
                    }
